$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force -Path $directory | Out-Null

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)

  Write-Host "Criado/atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "app\api\admin\scan\route.ts" @"

"@

Write-Base64File "app\admin\scanner\page.tsx" @"

"@

# Adiciona link para scanner detalhado na pagina admin, se existir.
$adminPage = Join-Path $project "app\admin\page.tsx"

if (Test-Path -LiteralPath $adminPage) {
  $content = [System.IO.File]::ReadAllText($adminPage)

  if ($content -notmatch "/admin/scanner") {
    $link = @'
                <Link href="/admin/scanner" className="rounded-2xl bg-black px-5 py-4 text-center font-black text-white">
                  Abrir scanner detalhado
                </Link>
'@

    if ($content -match "Rodar scanner agora") {
      $content = $content.Replace("Rodar scanner agora", "Rodar scanner agora")
      $content = $content.Replace("</section>`r`n`r`n              <section className=""rounded-[2rem] border border-blue-100 bg-white p-5 shadow-xl shadow-blue-950/5"">", "$link`r`n              </section>`r`n`r`n              <section className=""rounded-[2rem] border border-blue-100 bg-white p-5 shadow-xl shadow-blue-950/5"">")
      [System.IO.File]::WriteAllText($adminPage, $content, $utf8NoBom)
      Write-Host "Link do scanner detalhado tentando ser adicionado ao Admin." -ForegroundColor Cyan
    } else {
      Write-Host "Pagina admin encontrada, mas nao consegui inserir o link automaticamente. Use /admin/scanner direto." -ForegroundColor Yellow
    }
  }
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Scanner detalhado instalado." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
